'use client';
import { useAuth } from '@/context/authContext';
import { useEffect, useState } from 'react';
import { ArrowDownTrayIcon } from '@heroicons/react/24/outline';
import styles from '@/styles/admin-index.module.css';

export default function AdminReportesPage() {
  const { user } = useAuth();
  const [reporte, setReporte] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [reporteSeleccionado, setReporteSeleccionado] = useState('resumen');
  const [grados, setGrados] = useState<any[]>([]);
  const [materias, setMaterias] = useState<any[]>([]);
  const [periodos, setPeriodos] = useState<any[]>([]);
  const [gradoId, setGradoId] = useState('');
  const [materiaId, setMateriaId] = useState('');
  const [periodoId, setPeriodoId] = useState('');

  useEffect(() => {
    if (!user) return;
    loadOpcionesFiltro();
  }, [user]);

  const loadOpcionesFiltro = async () => {
    try {
      const idToken = await user?.getIdToken();

      // Cargar grados
      const gradosRes = await fetch('/api/admin/grados', {
        headers: { Authorization: `Bearer ${idToken}` },
      });
      if (gradosRes.ok) {
        const data = await gradosRes.json();
        setGrados(data.grados || []);
      }

      // Cargar materias
      const materiasRes = await fetch('/api/admin/asignaturas', {
        headers: { Authorization: `Bearer ${idToken}` },
      });
      if (materiasRes.ok) {
        const data = await materiasRes.json();
        setMaterias(data.asignaturas || []);
      }

      // Cargar períodos
      const periodosRes = await fetch('/api/admin/periodos', {
        headers: { Authorization: `Bearer ${idToken}` },
      });
      if (periodosRes.ok) {
        const data = await periodosRes.json();
        setPeriodos(data.periodos || []);
      }
    } catch (err) {
      console.error('Error cargando opciones:', err);
    }
  };

  const generarReporte = async () => {
    try {
      setLoading(true);
      setError('');
      const idToken = await user?.getIdToken();

      let url = `/api/admin/reportes?tipo=${reporteSeleccionado}`;

      if (reporteSeleccionado === 'estudiantes-grado' && gradoId) {
        url += `&gradoId=${gradoId}`;
      } else if (reporteSeleccionado === 'notas-materia' && materiaId && periodoId) {
        url += `&materiaId=${materiaId}&periodoId=${periodoId}`;
      } else if (reporteSeleccionado === 'asistencia' && materiaId) {
        url += `&materiaId=${materiaId}`;
      }

      const response = await fetch(url, {
        headers: { Authorization: `Bearer ${idToken}` },
      });

      if (response.ok) {
        const data = await response.json();
        setReporte(data.reporte);
      } else {
        setError('Error al generar reporte');
      }
    } catch (err) {
      console.error('Error generando reporte:', err);
      setError('Error al generar reporte');
    } finally {
      setLoading(false);
    }
  };

  const exportarCSV = () => {
    if (!reporte) return;

    let csv = '';

    if (reporteSeleccionado === 'resumen') {
      csv = 'Métrica,Valor\n';
      Object.entries(reporte.resumen).forEach(([key, value]) => {
        csv += `${key},${value}\n`;
      });
    } else if (reporteSeleccionado === 'estudiantes-grado') {
      csv = 'Nombre,Email,Documento\n';
      reporte.estudiantes?.forEach((est: any) => {
        csv += `${est.estudiante.name},${est.estudiante.email},${est.estudiante.documentNumber}\n`;
      });
    } else if (reporteSeleccionado === 'notas-materia') {
      csv = 'Estudiante,Email,Nota\n';
      reporte.notas?.forEach((nota: any) => {
        csv += `${nota.estudiante.name},${nota.estudiante.email},${nota.valor}\n`;
      });
    } else if (reporteSeleccionado === 'asistencia') {
      csv = 'Estudiante,Presente,Ausente,Total,Asistencia %\n';
      reporte.asistenciaPorEstudiante?.forEach((asist: any) => {
        const porcentaje = asist.total > 0 ? ((asist.presente / asist.total) * 100).toFixed(1) : 0;
        csv += `${asist.estudiante.name},${asist.presente},${asist.ausente},${asist.total},${porcentaje}%\n`;
      });
    }

    const blob = new Blob([csv], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `reporte-${reporteSeleccionado}-${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
  };

  return (
    <div className={styles.container}>
      <h1 className={styles.title}>Generador de Reportes</h1>

      {error && <div style={{ color: 'red', marginBottom: '1rem', padding: '0.5rem', backgroundColor: '#fee', borderRadius: '0.375rem' }}>{error}</div>}

      <div style={{ backgroundColor: '#f9f9f9', padding: '1.5rem', borderRadius: '0.5rem', marginBottom: '2rem', border: '1px solid #ddd' }}>
        <h2 style={{ marginTop: 0 }}>Seleccionar Reporte</h2>

        <div style={{ marginBottom: '1rem' }}>
          <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 'bold' }}>Tipo de Reporte</label>
          <select
            value={reporteSeleccionado}
            onChange={(e) => {
              setReporteSeleccionado(e.target.value);
              setReporte(null);
            }}
            style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '0.375rem' }}
          >
            <option value="resumen">Resumen General</option>
            <option value="estudiantes-grado">Estudiantes por Grado</option>
            <option value="notas-materia">Notas por Materia</option>
            <option value="asistencia">Asistencia por Materia</option>
            <option value="docentes">Docentes y Asignaciones</option>
          </select>
        </div>

        {reporteSeleccionado === 'estudiantes-grado' && (
          <div style={{ marginBottom: '1rem' }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 'bold' }}>Grado *</label>
            <select
              value={gradoId}
              onChange={(e) => setGradoId(e.target.value)}
              style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '0.375rem' }}
            >
              <option value="">Selecciona un grado</option>
              {grados.map(g => (
                <option key={g.id} value={g.id}>{g.nombre} {g.seccion}</option>
              ))}
            </select>
          </div>
        )}

        {reporteSeleccionado === 'notas-materia' && (
          <>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
              <div>
                <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 'bold' }}>Materia *</label>
                <select
                  value={materiaId}
                  onChange={(e) => setMateriaId(e.target.value)}
                  style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '0.375rem' }}
                >
                  <option value="">Selecciona una materia</option>
                  {materias.map(m => (
                    <option key={m.id} value={m.id}>{m.nombre}</option>
                  ))}
                </select>
              </div>
              <div>
                <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 'bold' }}>Periodo *</label>
                <select
                  value={periodoId}
                  onChange={(e) => setPeriodoId(e.target.value)}
                  style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '0.375rem' }}
                >
                  <option value="">Selecciona un período</option>
                  {periodos.map(p => (
                    <option key={p.id} value={p.id}>{p.nombre}</option>
                  ))}
                </select>
              </div>
            </div>
          </>
        )}

        {reporteSeleccionado === 'asistencia' && (
          <div style={{ marginBottom: '1rem' }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 'bold' }}>Materia *</label>
            <select
              value={materiaId}
              onChange={(e) => setMateriaId(e.target.value)}
              style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '0.375rem' }}
            >
              <option value="">Selecciona una materia</option>
              {materias.map(m => (
                <option key={m.id} value={m.id}>{m.nombre}</option>
              ))}
            </select>
          </div>
        )}

        <button
          onClick={generarReporte}
          disabled={loading}
          style={{
            padding: '0.5rem 1.5rem',
            backgroundColor: '#0066cc',
            color: 'white',
            border: 'none',
            borderRadius: '0.375rem',
            cursor: loading ? 'not-allowed' : 'pointer',
            opacity: loading ? 0.6 : 1,
            fontWeight: 'bold',
          }}
        >
          {loading ? 'Generando...' : 'Generar Reporte'}
        </button>
      </div>

      {reporte && (
        <div style={{ backgroundColor: 'white', padding: '1.5rem', borderRadius: '0.5rem', border: '1px solid #ddd' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
            <h2 style={{ margin: 0 }}>Resultado del Reporte</h2>
            <button
              onClick={exportarCSV}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                padding: '0.5rem 1rem',
                backgroundColor: '#28a745',
                color: 'white',
                border: 'none',
                borderRadius: '0.375rem',
                cursor: 'pointer',
              }}
            >
              <ArrowDownTrayIcon style={{ width: 16, height: 16 }} />
              Descargar CSV
            </button>
          </div>

          {reporteSeleccionado === 'resumen' && (
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr style={{ backgroundColor: '#f0f0f0' }}>
                  <th style={{ padding: '0.75rem', textAlign: 'left', borderBottom: '1px solid #ddd' }}>Métrica</th>
                  <th style={{ padding: '0.75rem', textAlign: 'right', borderBottom: '1px solid #ddd' }}>Valor</th>
                </tr>
              </thead>
              <tbody>
                {Object.entries(reporte.resumen || {}).map(([key, value], idx) => (
                  <tr key={key} style={{ backgroundColor: idx % 2 === 0 ? '#fff' : '#f9f9f9' }}>
                    <td style={{ padding: '0.75rem', borderBottom: '1px solid #eee' }}>{key}</td>
                    <td style={{ padding: '0.75rem', textAlign: 'right', borderBottom: '1px solid #eee', fontWeight: 'bold' }}>{String(value)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}

          {reporteSeleccionado === 'estudiantes-grado' && (
            <>
              <p style={{ margin: '0.5rem 0', fontWeight: 'bold' }}>Grado: {reporte.grado?.nombre} {reporte.grado?.seccion}</p>
              <p style={{ margin: '0.5rem 0', color: '#666' }}>Total de estudiantes: {reporte.totalEstudiantes}</p>
              <table style={{ width: '100%', borderCollapse: 'collapse', marginTop: '1rem' }}>
                <thead>
                  <tr style={{ backgroundColor: '#f0f0f0' }}>
                    <th style={{ padding: '0.75rem', textAlign: 'left', borderBottom: '1px solid #ddd' }}>Nombre</th>
                    <th style={{ padding: '0.75rem', textAlign: 'left', borderBottom: '1px solid #ddd' }}>Email</th>
                  </tr>
                </thead>
                <tbody>
                  {reporte.estudiantes?.map((est: any, idx: number) => (
                    <tr key={est.id} style={{ backgroundColor: idx % 2 === 0 ? '#fff' : '#f9f9f9' }}>
                      <td style={{ padding: '0.75rem', borderBottom: '1px solid #eee' }}>{est.estudiante.name}</td>
                      <td style={{ padding: '0.75rem', borderBottom: '1px solid #eee' }}>{est.estudiante.email}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </>
          )}

          {reporteSeleccionado === 'notas-materia' && (
            <>
              <p style={{ margin: '0.5rem 0', fontWeight: 'bold' }}>Materia: {reporte.materia?.nombre} ({reporte.materia?.codigo})</p>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1rem', marginBottom: '1rem', padding: '1rem', backgroundColor: '#f9f9f9', borderRadius: '0.5rem' }}>
                <div><strong>Promedio:</strong> {reporte.estadisticas?.promedio}</div>
                <div><strong>Máxima:</strong> {reporte.estadisticas?.notaMaxima}</div>
                <div><strong>Mínima:</strong> {reporte.estadisticas?.notaMinima}</div>
                <div><strong>Estudiantes:</strong> {reporte.estadisticas?.totalEstudiantes}</div>
              </div>
              <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead>
                  <tr style={{ backgroundColor: '#f0f0f0' }}>
                    <th style={{ padding: '0.75rem', textAlign: 'left', borderBottom: '1px solid #ddd' }}>Estudiante</th>
                    <th style={{ padding: '0.75rem', textAlign: 'right', borderBottom: '1px solid #ddd' }}>Nota</th>
                  </tr>
                </thead>
                <tbody>
                  {reporte.notas?.map((nota: any, idx: number) => (
                    <tr key={nota.id} style={{ backgroundColor: idx % 2 === 0 ? '#fff' : '#f9f9f9' }}>
                      <td style={{ padding: '0.75rem', borderBottom: '1px solid #eee' }}>{nota.estudiante.name}</td>
                      <td style={{ padding: '0.75rem', textAlign: 'right', borderBottom: '1px solid #eee', fontWeight: 'bold' }}>{nota.valor}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </>
          )}

          {reporteSeleccionado === 'asistencia' && (
            <>
              <p style={{ margin: '0.5rem 0', fontWeight: 'bold' }}>Materia: {reporte.materia?.nombre}</p>
              <table style={{ width: '100%', borderCollapse: 'collapse', marginTop: '1rem' }}>
                <thead>
                  <tr style={{ backgroundColor: '#f0f0f0' }}>
                    <th style={{ padding: '0.75rem', textAlign: 'left', borderBottom: '1px solid #ddd' }}>Estudiante</th>
                    <th style={{ padding: '0.75rem', textAlign: 'center', borderBottom: '1px solid #ddd' }}>Presente</th>
                    <th style={{ padding: '0.75rem', textAlign: 'center', borderBottom: '1px solid #ddd' }}>Ausente</th>
                    <th style={{ padding: '0.75rem', textAlign: 'center', borderBottom: '1px solid #ddd' }}>Total</th>
                  </tr>
                </thead>
                <tbody>
                  {reporte.asistenciaPorEstudiante?.map((asist: any, idx: number) => (
                    <tr key={asist.estudiante.id} style={{ backgroundColor: idx % 2 === 0 ? '#fff' : '#f9f9f9' }}>
                      <td style={{ padding: '0.75rem', borderBottom: '1px solid #eee' }}>{asist.estudiante.name}</td>
                      <td style={{ padding: '0.75rem', textAlign: 'center', borderBottom: '1px solid #eee', color: '#28a745', fontWeight: 'bold' }}>{asist.presente}</td>
                      <td style={{ padding: '0.75rem', textAlign: 'center', borderBottom: '1px solid #eee', color: '#dc3545', fontWeight: 'bold' }}>{asist.ausente}</td>
                      <td style={{ padding: '0.75rem', textAlign: 'center', borderBottom: '1px solid #eee' }}>{asist.total}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </>
          )}

          {reporteSeleccionado === 'docentes' && (
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr style={{ backgroundColor: '#f0f0f0' }}>
                  <th style={{ padding: '0.75rem', textAlign: 'left', borderBottom: '1px solid #ddd' }}>Docente</th>
                  <th style={{ padding: '0.75rem', textAlign: 'center', borderBottom: '1px solid #ddd' }}>Materias</th>
                  <th style={{ padding: '0.75rem', textAlign: 'center', borderBottom: '1px solid #ddd' }}>Asignaciones</th>
                </tr>
              </thead>
              <tbody>
                {reporte.docentes?.map((doc: any, idx: number) => (
                  <tr key={doc.id} style={{ backgroundColor: idx % 2 === 0 ? '#fff' : '#f9f9f9' }}>
                    <td style={{ padding: '0.75rem', borderBottom: '1px solid #eee' }}>
                      <strong>{doc.name}</strong>
                      <div style={{ fontSize: '0.875rem', color: '#666' }}>{doc.email}</div>
                    </td>
                    <td style={{ padding: '0.75rem', textAlign: 'center', borderBottom: '1px solid #eee' }}>{doc.totalMaterias}</td>
                    <td style={{ padding: '0.75rem', textAlign: 'center', borderBottom: '1px solid #eee' }}>{doc.asignacionesGradoMateria}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      )}
    </div>
  );
}
